import React, { useMemo, useState } from 'react'
import { Movie } from '../types/Movie'
import MovieCard from './MovieCard'

interface Props {
  title: string
  movies: Movie[]
  emptyText?: string
}

const MovieList: React.FC<Props> = ({ title, movies, emptyText }) => {
  const [shuffleKey, setShuffleKey] = useState(0)

  const list = useMemo(() => {
    const arr = [...movies]
    if (shuffleKey > 0) {
      for (let i = arr.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1))
        const temp = arr[i]
        arr[i] = arr[j]
        arr[j] = temp
      }
    }
    return arr
  }, [movies, shuffleKey])

  return (
    <section className="mb-10">
      <div className="flex items-center justify-between mb-4">
        <h2 className="text-xl sm:text-2xl font-semibold text-white">{title}</h2>
        <div className="flex items-center gap-2">
          <button onClick={() => setShuffleKey(shuffleKey + 1)} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Shuffle</button>
        </div>
      </div>
      {list.length === 0 ? (
        <div className="p-6 rounded-xl border border-gray-800 bg-gray-900/40 text-gray-300">
          {emptyText || 'No movies to display right now.'}
        </div>
      ) : (
        <div className="grid gap-4 sm:gap-5 grid-cols-2 sm:grid-cols-3 lg:grid-cols-4 xl:grid-cols-5">
          {list.map((m) => (
            <MovieCard key={m.id} movie={m} />
          ))}
        </div>
      )}
    </section>
  )
}

export default MovieList

