import React, { useEffect, useMemo, useState } from 'react'
import { useParams, useNavigate } from 'react-router-dom'
import { useMoviesContext } from '../context/MoviesContext'
import MovieList from '../components/MovieList'

const Watch: React.FC = () => {
  const { id } = useParams()
  const { getMovieById, byGenre, toggleFavorite, isFavorite } = useMoviesContext()
  const navigate = useNavigate()
  const movie = useMemo(() => (id ? getMovieById(id) : undefined), [id, getMovieById])

  const [playing, setPlaying] = useState(false)
  const [progress, setProgress] = useState(0)
  const [liked, setLiked] = useState(false)

  useEffect(() => {
    let t: number | undefined
    if (playing) {
      t = window.setInterval(() => {
        setProgress((p) => {
          const np = p + 1.5
          if (np >= 100) {
            window.clearInterval(t)
            return 100
          }
          return np
        })
      }, 200)
    }
    return () => {
      window.clearInterval(t)
    }
  }, [playing])

  if (!movie) {
    return (
      <div className="max-w-6xl mx-auto px-4 py-16">
        <div className="p-8 rounded-xl bg-gray-900 border border-gray-800 text-center">
          <h2 className="text-2xl font-semibold text-white">Movie not found</h2>
          <p className="text-gray-400 mt-2">The title you're looking for doesn't exist or was removed.</p>
          <button onClick={() => navigate('/')} className="mt-4 px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">Back Home</button>
        </div>
      </div>
    )
  }

  const recommendations = byGenre(movie.genres[0]).filter((m) => m.id !== movie.id).slice(0, 10)
  const fav = isFavorite(movie.id)

  return (
    <div>
      <section className="relative">
        <div className="absolute inset-0">
          <img src={movie.backdrop} alt={movie.title} className="w-full h-full object-cover opacity-70" />
          <div className="absolute inset-0 bg-gradient-to-t from-gray-950 via-gray-950/70 to-transparent" />
        </div>
        <div className="relative max-w-6xl mx-auto px-4 pt-8 pb-10">
          <div className="grid grid-cols-1 lg:grid-cols-5 gap-6 items-end">
            <div className="lg:col-span-3">
              <div className="rounded-xl overflow-hidden border border-gray-800 bg-gray-900/60 shadow-md">
                <div className="aspect-video w-full relative flex items-center justify-center">
                  <img src={movie.backdrop} alt={movie.title} className="absolute inset-0 w-full h-full object-cover opacity-60" />
                  <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent" />
                  <button onClick={() => setPlaying(!playing)} className="z-10 px-6 py-3 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition shadow-md">
                    {playing ? 'Pause' : 'Play'}
                  </button>
                </div>
                <div className="px-4 py-3">
                  <div className="w-full h-2 bg-gray-800 rounded-full overflow-hidden">
                    <div className="h-full bg-blue-600 transition-all" style={{ width: `${progress}%` }} />
                  </div>
                  <div className="mt-2 text-xs text-gray-400">Progress: {Math.floor(progress)}%</div>
                </div>
              </div>
            </div>
            <div className="lg:col-span-2">
              <div className="space-y-3">
                <h1 className="text-3xl font-bold text-white">{movie.title}</h1>
                <div className="flex items-center gap-3 text-gray-300">
                  <span className="px-2 py-0.5 rounded bg-gray-900/70 border border-gray-800">{movie.year}</span>
                  <span>{movie.duration}</span>
                  <span className="text-amber-400">★ {movie.rating.toFixed(1)}</span>
                </div>
                <p className="text-gray-200">{movie.description}</p>
                <div className="flex flex-wrap gap-2">
                  {movie.genres.map((g) => (
                    <span key={g} className="text-xs px-2 py-1 rounded-full bg-gray-900/70 border border-gray-800 text-gray-300">{g}</span>
                  ))}
                </div>
                <div className="pt-2 flex items-center gap-2">
                  <button onClick={() => setPlaying(!playing)} className="px-4 py-2 rounded-lg bg-blue-600 text-white hover:bg-blue-500 transition">{playing ? 'Pause' : 'Play'}</button>
                  <button onClick={() => toggleFavorite(movie.id)} className={`px-4 py-2 rounded-lg transition ${fav ? 'bg-green-600 hover:bg-green-500 text-white' : 'bg-gray-900/80 hover:bg-gray-800 text-white border border-gray-700'}`}>{fav ? 'Added to List' : 'Add to My List'}</button>
                  <button onClick={() => setLiked(!liked)} className={`px-4 py-2 rounded-lg transition ${liked ? 'bg-pink-600 hover:bg-pink-500 text-white' : 'bg-gray-900/80 hover:bg-gray-800 text-white border border-gray-700'}`}>{liked ? 'Liked' : 'Like'}</button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>

      <section className="max-w-6xl mx-auto px-4 py-10">
        <MovieList title="Because you watched" movies={recommendations} emptyText="No recommendations yet." />
      </section>
    </div>
  )
}

export default Watch

