import React, { createContext, useContext, useEffect, useMemo, useState } from 'react'
import { useMovies } from '../hooks/useMovies'
import { Movie } from '../types/Movie'

interface Ctx {
  movies: Movie[]
  loading: boolean
  error: string | null
  searchQuery: string
  setSearchQuery: (q: string) => void
  selectedGenre: string
  setSelectedGenre: (g: string) => void
  sortOrder: 'popular' | 'rating' | 'year' | 'title'
  setSortOrder: (v: 'popular' | 'rating' | 'year' | 'title') => void
  isFavorite: (id: string) => boolean
  toggleFavorite: (id: string) => void
  favoritesList: Movie[]
  genres: string[]
  filtered: Movie[]
  trending: Movie[]
  topRated: Movie[]
  newReleases: Movie[]
  byGenre: (g: string) => Movie[]
  getMovieById: (id: string) => Movie | undefined
}

const MoviesContext = createContext<Ctx | null>(null)

export const MoviesProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const { movies: baseMovies, loading, error } = useMovies()
  const [searchQuery, setSearchQuery] = useState('')
  const [selectedGenre, setSelectedGenre] = useState('All')
  const [sortOrder, setSortOrder] = useState<'popular' | 'rating' | 'year' | 'title'>('popular')
  const [favorites, setFavorites] = useState<string[]>(() => {
    try {
      const raw = localStorage.getItem('cinestream:favorites')
      return raw ? JSON.parse(raw) : []
    } catch {
      return []
    }
  })

  useEffect(() => {
    localStorage.setItem('cinestream:favorites', JSON.stringify(favorites))
  }, [favorites])

  const genres = useMemo(() => {
    const s = new Set<string>()
    baseMovies.forEach((m) => m.genres.forEach((g) => s.add(g)))
    return Array.from(s).sort()
  }, [baseMovies])

  const normalized = useMemo(() => {
    let arr = [...baseMovies]
    if (searchQuery.trim()) {
      const q = searchQuery.toLowerCase()
      arr = arr.filter((m) =>
        m.title.toLowerCase().includes(q) ||
        m.genres.some((g) => g.toLowerCase().includes(q)) ||
        m.description.toLowerCase().includes(q)
      )
    }
    if (selectedGenre !== 'All') {
      arr = arr.filter((m) => m.genres.includes(selectedGenre))
    }
    switch (sortOrder) {
      case 'rating':
        arr.sort((a, b) => b.rating - a.rating)
        break
      case 'year':
        arr.sort((a, b) => b.year - a.year)
        break
      case 'title':
        arr.sort((a, b) => a.title.localeCompare(b.title))
        break
      default:
        arr.sort((a, b) => Number(!!b.trending) - Number(!!a.trending))
    }
    return arr
  }, [baseMovies, searchQuery, selectedGenre, sortOrder])

  const trending = useMemo(() => baseMovies.filter((m) => m.trending), [baseMovies])
  const topRated = useMemo(() => baseMovies.filter((m) => m.topRated || m.rating >= 8.3), [baseMovies])
  const newReleases = useMemo(() => baseMovies.filter((m) => m.year >= 2022), [baseMovies])

  const byGenre = (g: string) => baseMovies.filter((m) => m.genres.includes(g))

  const isFavorite = (id: string) => favorites.includes(id)
  const toggleFavorite = (id: string) => {
    setFavorites((prev) => (prev.includes(id) ? prev.filter((x) => x !== id) : [id, ...prev]))
  }

  const favoritesList = useMemo(() => baseMovies.filter((m) => favorites.includes(m.id)), [baseMovies, favorites])

  const getMovieById = (id: string) => baseMovies.find((m) => m.id === id)

  const value: Ctx = {
    movies: baseMovies,
    loading,
    error,
    searchQuery,
    setSearchQuery,
    selectedGenre,
    setSelectedGenre,
    sortOrder,
    setSortOrder,
    isFavorite,
    toggleFavorite,
    favoritesList,
    genres,
    filtered: normalized,
    trending,
    topRated,
    newReleases,
    byGenre,
    getMovieById,
  }

  return <MoviesContext.Provider value={value}>{children}</MoviesContext.Provider>
}

export const useMoviesContext = (): Ctx => {
  const ctx = useContext(MoviesContext)
  if (!ctx) throw new Error('useMoviesContext must be used inside MoviesProvider')
  return ctx
}
